const rawInput = $input.first().json;
const input = (rawInput.body && typeof rawInput.body === 'object') ? rawInput.body : rawInput;
const searchParams = {
  q: `site:linkedin.com/in/ "${input.keyword}" "${input.city}"`,
  num: Math.min(input.limit || 10, 25)
};
return [{ json: { ...input, serper_search_params: searchParams } }];

const webhookRaw = $('On Webhook Trigger').first().json;
const webhook = (webhookRaw.body && typeof webhookRaw.body === 'object') ? webhookRaw.body : webhookRaw;

const results = $input.first().json.organic || [];
const leadSourceId = webhook.lead_source_id || null;

const leads = results.map(p => {
  const isCompany = p.link && p.link.includes('/company/');
  let firstName = 'Unknown';
  let lastName = '';
  let companyName = '';
  let jobTitle = '';

  if (isCompany) {
    companyName = (p.title || '').replace(' | LinkedIn', '').replace(' - LinkedIn', '').trim();
    firstName = 'Company';
  } else {
    const titleParts = (p.title || '').replace(' | LinkedIn', '').replace(' - LinkedIn', '').split(' - ');
    const name = titleParts[0] ? titleParts[0].trim() : 'Unknown';
    const nameParts = name.split(' ');
    firstName = nameParts[0] || 'Unknown';
    lastName = nameParts.slice(1).join(' ') || '';

    jobTitle = titleParts[1] ? titleParts[1].trim() : '';
    // Use empty string instead of 'Unknown Company' to prevent merging unrelated leads in backend
    companyName = titleParts.length > 2 ? titleParts.slice(2).join(' ').trim() : titleParts.length === 2 && !titleParts[1].includes(' at ') && !titleParts[1].toLowerCase().includes('freelance') ? titleParts[1].trim() : '';
  }

  return {
    first_name: firstName,
    last_name: lastName,
    company_name: companyName,
    email: '',
    phone: '',
    job_title: jobTitle,
    city: webhook.city || '',
    province: '',
    lead_source_id: leadSourceId,
    estimated_value: 0,
    // Use LinkedIn URL as place_id to guarantee unique deduplication per person
    place_id: p.link || '',
    website: p.link || '',
    notes: [
      `Source: LinkedIn via Serper Google Search`,
      `LinkedIn URL: ${p.link || 'N/A'}`,
      `Headline/Snippet: ${p.snippet || 'N/A'}`,
      `Keyword: ${webhook.keyword}`
    ].join('\n')
  };
});

return [{ json: { leads: leads, source: 'linkedin' } }];
